+            "command": "bash -c 'if [ -n \"$VI_CLI_PATH\" ]; then exec $VI_CLI_PATH claudecode hook; else exec npx -y @vibeinsights/cli@latest claudecode hook; fi'"
+          }
+        ]
+      }
+    ]
+  }
